hooks.command:
FILE=$(jq -r '.tool_input.file_path // empty' 2>/dev/null); if echo "$FILE" | grep -qE '\.(html|css)$'; then python3 -c "
import re, sys
with open('$FILE', encoding='utf-8') as f:
    content = f.read()
warnings = []
# ロゴ・フッター・short labels に white-space:nowrap がないか
for m in re.finditer(r'\.(footer-logo|nav-logo-text|hero-badge)[^}]*}', content, re.DOTALL):
    if 'nowrap' not in m.group():
        warnings.append(f'⚠ {m.group(0)[:50].strip()}... に white-space:nowrap がない可能性')
# clampなしのpx固定タイトルを検出
for m in re.finditer(r'(section-title|contact-title|methods-title)[^}]*font-size:\s*(\d+)px', content):
    warnings.append(f'⚠ {m.group(1)} に clamp なしの固定 {m.group(2)}px フォントサイズ')
# モバイル用containerのpadding確認
if 'max-width: 960px' in content or 'max-width:960px' in content:
    if 'max-width: 540px' not in content and '@media (max-width: 540px)' not in content:
        warnings.append('⚠ 540px以下のモバイルブレークポイントがない')
if warnings:
    print(chr(10).join(warnings))
    sys.exit(2)
" 2>/dev/null; fi; exit 0
